import sqlite3
import base64
import hmac
import hashlib
import re
import time
from datetime import datetime
from flask import Flask, render_template, request, jsonify, g
import config

app = Flask(__name__)
app.secret_key = config.SECRET_KEY

def get_db():
    db = getattr(g, '_database', None)
    if db is None:
        db = g._database = sqlite3.connect(config.DATABASE_PATH)
        db.row_factory = sqlite3.Row
    return db

@app.teardown_appcontext
def close_connection(exception):
    db = getattr(g, '_database', None)
    if db is not None:
        db.close()

def waf_filter(val):
    # Normalize input
    val = val.upper()
    # Layer 1: Strict Whitespace and Comment Blocking
    if re.search(r"[\s\r\n\t\f\v]", val):
        return False
    if any(marker in val for marker in ['--', '/*', '*/', '#', 'U00', '0X']):
        return False

    # Layer 2: Expanded Keyword Blacklist
    # Blocking SUBSTR, INSTR, and comparison operators like LIKE/GLOB forces binary search on the full string.
    # Blocking || prevents common string concatenation bypasses.
    blacklist = [
        'UNION', 'OR', 'AND', 'LIMIT', 'JOIN', 'HEX', 
        'CASE', 'WHEN', 'THEN', 'ELSE', 
        'SUBSTR', 'INSTR', 'GLOB', 'MATCH', 'LIKE',
        'EXISTS', 'IN', 'BETWEEN', 'LENGTH', 'REPLACE',
        'TRIM', 'LTRIM', 'RTRIM', 'CHAR', 'UNICODE'
    ]
    for word in blacklist:
        if re.search(rf'\b{re.escape(word)}\b', val):
            return False
    if '||' in val:
        return False
    return True

def get_result_signature(result_id):
    # Shifting oracle: The valid signature for a "True" or "False" result changes every 60 seconds.
    system_id = "AETH-7782-X"
    time_step = datetime.utcnow().strftime('%Y-%m-%d-%H-%M')
    salt = hmac.new(system_id.encode(), time_step.encode(), hashlib.sha256).hexdigest()

    # Hash the result concatenated with the salt to prevent static boolean analysis
    val_to_hash = f"{result_id}:{salt}" if result_id else f"None:{salt}"
    return hashlib.sha256(val_to_hash.encode()).hexdigest()

def check_auth():
    # Multi-factor authentication required for the API
    if request.headers.get('X-Internal-Service') != 'telemetry-gateway':
        return False

    system_id = "AETH-7782-X"
    try:
        challenge = request.headers.get('X-Aetheris-Challenge', '')
        token = request.headers.get('X-Aetheris-Token', '')

        # Verify challenge is recent and tied to the request (time-based window)
        # Attacker must fetch a valid challenge from the /api/v1/auth/challenge endpoint first
        expected_msg = datetime.utcnow().strftime('%Y-%m-%d-%H-%M')
        msg = f"{challenge}:{expected_msg}"
        expected_token = hmac.new(system_id.encode(), msg.encode(), hashlib.sha256).hexdigest()

        if not hmac.compare_digest(token, expected_token):
            return False
    except:
        return False
    return True

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/dashboard')
def dashboard():
    db = get_db()
    satellites = db.execute('SELECT * FROM satellites').fetchall()
    return render_template('dashboard.html', satellites=satellites)

@app.route('/telemetry/<int:sat_id>')
def telemetry(sat_id):
    db = get_db()
    satellite = db.execute('SELECT * FROM satellites WHERE id = ?', (sat_id,)).fetchone()
    logs = db.execute('SELECT * FROM propulsion_logs WHERE sat_id = ? ORDER BY timestamp DESC LIMIT 10', (sat_id,)).fetchall()
    return render_template('telemetry.html', satellite=satellite, logs=logs)

@app.route('/api/v1/auth/challenge', methods=['GET'])
def get_challenge():
    # Provides the necessary ephemeral challenge for the API HMAC
    ts = datetime.utcnow().strftime('%Y-%m-%d-%H-%M')
    challenge = hashlib.md5(f"{ts}-{request.remote_addr}".encode()).hexdigest()[:12]
    return jsonify({"challenge": challenge, "timestamp": ts})

@app.route('/api/v1/telemetry/integrity', methods=['POST'])
def integrity_check():
    # Artificial delay to slow down automated extraction
    time.sleep(0.4)

    if not check_auth():
        return jsonify({"error": "Gateway Authentication Failure"}), 403

    data = request.get_json() or {}
    sensor_id = str(data.get('sensor_id', ''))

    if not waf_filter(sensor_id):
        return jsonify({"error": "Malicious Payload Signature Detected"}), 400

    try:
        db = get_db()
        # Vulnerable query via string formatting. Whitespace/comments blocked.
        # Requirement: Use equality chaining or numeric math to bypass lack of OR/AND/SUBSTR.
        query = f"SELECT id FROM propulsion_logs WHERE sensor_id = '{sensor_id}'"
        result = db.execute(query).fetchone()

        res_id = result['id'] if result else None
        sig = get_result_signature(res_id)

        return jsonify({"status": "Computed", "integrity_sig": sig})
    except Exception:
        # No error feedback
        return jsonify({"status": "Internal Processing Error"}), 500

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)

